                  className="flex-1 py-3 bg-transparent text-gray-300 border-none focus:outline-none focus:ring-0 placeholder-gray-600 font-mono text-sm min-w-0"
                />
              </div>
              {isRunning && (
                <button
                  type="button"
                  onClick={sendPanicStop}
