                  <h3 className="text-xl font-medium text-gray-500 mb-2">Navegador em Standby</h3>
                  <p className="text-sm">Envie um comando para iniciar a automa├º├úo.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
