export const Dashboard: React.FC = () => {
  const [adsData, setAdsData] = useState<AdData[]>([]);
  const [gaData, setGaData] = useState<GA4CityData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Mock Actions
  const handleImplement = (action: string) => {
    alert(`Acionando Maestro: Executando automa├º├úo para '${action}'...`);
  };

  const handleStudy = (topic: string) => {
    alert(`Abrindo base de conhecimento sobre: '${topic}'...`);
  };

  const fetchSpreadsheetData = async (): Promise<void> => {
    setIsLoading(true);
    try {
      const response = await fetch(
        'https://corsproxy.io/?url=' +
          encodeURIComponent(
            'https://docs.google.com/spreadsheets/d/1vAho1pFtyn8StKdZHrSrzSksFnY281g8BTA_hKbHsKw/export?format=csv'
          )
      );
      const csvText = await response.text();
      const rows = csvText.split('\n');
      const data: AdData[] = [];

      for (let i = 1; i < rows.length; i++) {
        const cols = rows[i].split(',');
        if (cols.length > 15 && cols[1]) {
          data.push({
            date: cols[1].trim(),
            campaign: cols[3].trim().replace(/^"|"$/g, ''),
            cliques: parseInt(cols[4]) || 0,
            impressoes: parseInt(cols[5]) || 0,
            custo: parseFloat(cols[8]) || 0,
            conversoes: parseFloat(cols[12]) || 0,
            cpa: parseFloat(cols[13]) || 0,
            roas: parseFloat(cols[16]) || 0,
          });
        }
      }

      if (data.length <= 1) throw new Error('No real data');
      setAdsData(data);
    } catch {
      // Dados mais robustos para gerar bons insights no fallback
      setAdsData([
        {
          date: '01/03',
          campaign: 'Search_Hipnose_Goi├ónia',
          cliques: 160,
          impressoes: 3100,
          custo: 60.5,
          conversoes: 7,
          cpa: 8.64,
          roas: 6.1,
        },
        {
          date: '02/03',
          campaign: 'Search_Hipnose_Goi├ónia',
          cliques: 185,
          impressoes: 3500,
          custo: 75.0,
          conversoes: 8,
          cpa: 9.37,
          roas: 5.8,
        },
        {
          date: '01/03',
          campaign: 'PMax_Conversao_TEA',
          cliques: 45,
          impressoes: 800,
          custo: 80.0,
          conversoes: 1,
          cpa: 80.0,
          roas: 1.2,
        },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchGA4Data = async (): Promise<void> => {
    try {
      const response = await fetch('http://localhost:8000/api/analytics/active-users');
      const data = await response.json();
      if (Array.isArray(data) && data.length > 0) setGaData(data);
      else throw new Error();
    } catch {
      setGaData([
        { city: 'Uberl├óndia', activeUsers: '6' },
        { city: 'Goi├ónia', activeUsers: '2' },
      ]);
    }
  };

  useEffect(() => {
    void fetchSpreadsheetData();
    void fetchGA4Data();
  }, []);

  // Processando dados em "Linguagem Natural"
  const totalCost = useMemo(() => adsData.reduce((acc, curr) => acc + curr.custo, 0), [adsData]);
  const totalConversions = useMemo(
    () => adsData.reduce((acc, curr) => acc + curr.conversoes, 0),
    [adsData]
  );

  const campaignSummary = useMemo(() => {
    const sum: Record<string, CampaignSummary> = {};
    adsData.forEach((ad) => {
      const name = ad.campaign || 'Desconhecida';
      if (!sum[name]) sum[name] = { name, custo: 0, conversoes: 0, cliques: 0 };
      sum[name].custo += ad.custo;
      sum[name].conversoes += ad.conversoes;
      sum[name].cliques += ad.cliques;
    });
    return Object.values(sum).map((c) => ({
      ...c,
      cpa: c.conversoes > 0 ? c.custo / c.conversoes : c.custo,
    }));
  }, [adsData]);

  // A melhor campanha DEVE ter mais de zero convers├Áes
  const bestCampaign = campaignSummary
    .filter((c) => c.conversoes > 0)
    .sort((a, b) => a.cpa - b.cpa)[0];
  const worstCampaign = campaignSummary
    .filter((c) => c.conversoes > 0 && c.custo > 0)
    .sort((a, b) => b.cpa - a.cpa)[0];
  // Campanhas gastando dinheiro sem nenhuma convers├úo e passando de R$ 5,00
  const bleedingCampaign = campaignSummary
    .filter((c) => c.conversoes === 0 && c.custo > 5)
    .sort((a, b) => b.custo - a.custo)[0];

