              title={`Sua campanha "${bestCampaign.name}" ├® um sucesso!`}
              description={`Ela trouxe ${bestCampaign.conversoes} convers├Áes num custo baix├¡ssimo de R$ ${bestCampaign.cpa.toFixed(2)} por paciente. O algoritmo j├í entendeu o seu p├║blico aqui.`}
              type="success"
              icon={TrendingUp}
              onImplement={() =>
                handleImplement('Aumentar verba em 20% na campanha ' + bestCampaign.name)
              }
              onStudy={() => handleStudy('Como escalar Campanhas no Google Ads')}
            />
          )}

          {/* Insight 2: Alerta de Oportunidades ou Fugas (CPA Caro) */}
          {worstCampaign &&
            worstCampaign !== bestCampaign &&
