interface PageSpeedData {
  id: string;
  fetchTime: string;
  scores: {
    performance: number;
    accessibility: number;
    'best-practices': number;
    seo: number;
  };
}

const ScoreGauge = ({ score, title }: { score: number; title: string }): JSX.Element => {
  const data = [
    { name: 'Score', value: score },
    { name: 'Remaining', value: 100 - score },
  ];

  const COLORS =
    score >= 90
      ? ['#2EED8F', '#1A1A1A']
      : score >= 50
        ? ['#FACC15', '#1A1A1A']
        : ['#EF4444', '#1A1A1A'];

  return (
    <div className="flex flex-col items-center gap-2 p-4 bg-[#111111] border border-gray-800/60 rounded-xl">
      <div className="relative w-24 h-24">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={data}
              innerRadius={30}
              outerRadius={45}
              startAngle={90}
              endAngle={450}
              dataKey="value"
              stroke="none"
            >
              {data.map((_entry, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index]} />
              ))}
            </Pie>
          </PieChart>
        </ResponsiveContainer>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-xl font-bold text-white">{score}</span>
        </div>
      </div>
      <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">{title}</span>
    </div>
  );
};

